# nginx.conf — minimal reverse proxy for an OpenAI-compatible server
server {
    listen 443 ssl;
    server_name llm.internal.corp;

    ssl_certificate /etc/ssl/llm.crt;
    ssl_certificate_key /etc/ssl/llm.key;

    location /v1/ {
        proxy_pass http://localhost:8080/v1/;
        proxy_set_header Authorization "Bearer $REAL_API_KEY";

        # Remove the incoming Authorization so clients never see the real key
        proxy_set_header X-Real-IP $remote_addr;

        # Optional: add a fixed HTTP header to identify this proxy
        add_header X-Proxy-Name "corp-llm-gateway";
    }
}
